39→type ShowHUD = (options: {
40→  icon?: ReactNode;
41→  title: string;
42→}) => string;
43→
44→interface PerformCopyOptions {
45→  hudTitle?: string;
46→  hudIcon?: ReactNode;
47→  onCopy?: () => void;
48→}
49→
50→export function performCopy(
51→  content: string,
52→  showHUD: ShowHUD,
53→  options?: PerformCopyOptions,
54→): void {
55→  copyToClipboard(content).catch(() => {});
56→  showHUD({
57→    icon: options?.hudIcon ?? <CopyHUDIcon />,
58→    title: options?.hudTitle ?? 'Copied to Clipboard',
59→  });
60→  options?.onCopy?.();
61→}
62→
63→interface CreateCopyActionOptions {
64→  content: string;
65→  title?: string;
66→  hudTitle?: string;
67→  hudIcon?: ReactNode;
68→  shortcut?: ReactNode;
69→  onCopy?: () => void;
70→}
71→
72→export function createCopyAction(
73→  options: CreateCopyActionOptions,
74→  showHUD: ShowHUD,
75→): DropdownAction {
76→  return {
77→    label: options.title ?? 'Copy',
78→    shortcut: options.shortcut,
79→    onClick: () => {
80→      performCopy(options.content, showHUD, {
81→        hudTitle: options.hudTitle,
82→        hudIcon: options.hudIcon,
83→        onCopy: options.onCopy,
84→      });
85→    },
86→  };
87→}
