119→const PIN_STATE_KEY = 'clipboard-pins';
120→const DELETED_KEY = 'clipboard-deleted';
121→
122→function loadInitialEntries(): ClipboardEntry[] {
123→  const pinState = storageGet(PIN_STATE_KEY, isBooleanRecord) ?? {};
124→  const deleted = new Set(storageGet(DELETED_KEY, isStringArray) ?? []);
125→  return MOCK_CLIPBOARD_ENTRIES.filter(e => !deleted.has(e.id)).map(e => ({
126→    ...e,
127→    pinned: e.id in pinState ? pinState[e.id]! : e.pinned,
128→  }));
129→}
130→
131→function saveEntryState(entries: ClipboardEntry[]) {
132→  const pinState: Record<string, boolean> = {};
133→  for (const e of entries) {
134→    pinState[e.id] = e.pinned;
135→  }
136→  storageSet(PIN_STATE_KEY, pinState);
137→
138→  const allIds = new Set(MOCK_CLIPBOARD_ENTRIES.map(e => e.id));
139→  const currentIds = new Set(entries.map(e => e.id));
140→  const deleted = [...allIds].filter(id => !currentIds.has(id));
141→  storageSet(DELETED_KEY, deleted);
142→}
