 98→const SNIPPETS_KEY = 'snippets';
 99→
100→interface StoredSnippet {
101→  id: string;
102→  name: string;
103→  keyword: string;
104→  content: string;
105→  category: string;
106→  tags: {
107→    text: string;
108→    color?: string;
109→  }[];
110→  createdAt: string;
111→}
112→
113→function isStoredTag(value: unknown): value is {
114→  text: string;
115→  color?: string;
116→} {
117→  if (!isRecord(value)) return false;
118→  if (typeof value.text !== 'string') return false;
119→  if ('color' in value && typeof value.color !== 'string') {
120→    return false;
121→  }
122→  return true;
123→}
124→
125→function isStoredSnippetArray(value: unknown): value is StoredSnippet[] {
126→  if (!Array.isArray(value)) return false;
127→  return value.every(
128→    v =>
129→      isRecord(v) &&
130→      typeof v.id === 'string' &&
131→      typeof v.name === 'string' &&
132→      typeof v.keyword === 'string' &&
133→      typeof v.content === 'string' &&
134→      typeof v.category === 'string' &&
135→      typeof v.createdAt === 'string' &&
136→      Array.isArray(v.tags) &&
137→      v.tags.every(isStoredTag),
138→  );
139→}
140→
141→function serializeEntries(entries: SnippetEntry[]): StoredSnippet[] {
142→  return entries.map(e => ({
143→    ...e,
144→    createdAt: e.createdAt.toISOString(),
145→  }));
146→}
147→
148→const TAG_COLOR_NAMES = new Set<string>(Object.keys(TAG_COLOR_HEX));
149→
150→function isTagColor(value: string): value is TagColor {
151→  return TAG_COLOR_NAMES.has(value);
152→}
153→
154→function deserializeEntries(stored: StoredSnippet[]): SnippetEntry[] {
155→  return stored.map(s => {
156→    const parsed = new Date(s.createdAt);
157→    const createdAt = Number.isNaN(parsed.getTime()) ? new Date() : parsed;
158→    return {
159→      ...s,
160→      category: isSnippetCategory(s.category) ? s.category : 'general',
161→      tags: s.tags.map(t => ({
162→        text: t.text,
163→        color: t.color && isTagColor(t.color) ? t.color : undefined,
164→      })),
165→      createdAt,
166→    };
167→  });
168→}
169→
170→function loadSnippets(): SnippetEntry[] {
171→  const stored = storageGet(SNIPPETS_KEY, isStoredSnippetArray);
172→  if (stored) return deserializeEntries(stored);
173→  return MOCK_SNIPPET_ENTRIES;
174→}
175→
176→function saveSnippets(entries: SnippetEntry[]) {
177→  storageSet(SNIPPETS_KEY, serializeEntries(entries));
178→}
