146→  const filtered = useMemo(() => {
147→    let items = entries;
148→    if (filterValue !== 'all') {
149→      items = items.filter(e => e.fileType === filterValue);
150→    }
151→    if (query) {
152→      items = items.filter(
153→        e => fuzzyMatch(query, e.name) || fuzzyMatch(query, e.path),
154→      );
155→    }
156→    return items;
157→  }, [
158→    entries,
159→    query,
160→    filterValue,
161→  ]);
162→
163→  const folders = useMemo(
164→    () => filtered.filter(e => e.fileType === 'folder'),
165→    [filtered],
166→  );
167→  const files = useMemo(
168→    () => filtered.filter(e => e.fileType !== 'folder'),
169→    [filtered],
170→  );
171→  const totalItemCount = filtered.length;
172→
173→  const flatItems = useMemo(
174→    () => [
175→      ...folders,
176→      ...files,
177→    ],
178→    [
179→      folders,
180→      files,
181→    ],
182→  );
183→
184→  useEffect(() => {
185→    if (selectedIndex >= totalItemCount && totalItemCount > 0) {
186→      setSelectedIndex(totalItemCount - 1);
187→    } else if (totalItemCount === 0) {
188→      setSelectedIndex(0);
189→    }
190→  }, [
191→    selectedIndex,
192→    totalItemCount,
193→  ]);
194→
195→  const selectedEntry = flatItems[selectedIndex];
196→
197→  const handleQueryChange = useCallback((value: string) => {
198→    setQuery(value);
199→    setSelectedIndex(0);
200→    setActionsOpen(false);
