205→    setSelectedIndex(0);
206→  }, []);
207→
208→  const handleActiveIndexChange = useCallback((index: number) => {
209→    setSelectedIndex(index);
210→    setActionsOpen(false);
211→  }, []);
212→
213→  const handleOpen = useCallback(() => {
214→    if (!selectedEntry) return;
215→    setActionsOpen(false);
216→    showHUD({
217→      icon: <OpenHUDIcon />,
218→      title: `Opened ${selectedEntry.name}`,
219→    });
220→  }, [
221→    selectedEntry,
222→    showHUD,
223→  ]);
