229→      icon: <OpenHUDIcon />,
230→      title: 'Revealed in Finder',
231→    });
232→  }, [
233→    selectedEntry,
234→    showHUD,
235→  ]);
236→
237→  const handleCopyPath = useCallback(() => {
238→    if (!selectedEntry) return;
239→    setActionsOpen(false);
240→    performCopy(selectedEntry.path, showHUD, {
241→      hudTitle: 'Path Copied',
242→    });
243→  }, [
244→    selectedEntry,
245→    showHUD,
246→  ]);
247→
248→  const handleDelete = useCallback(() => {
249→    if (!selectedEntry) return;
250→    const entryId = selectedEntry.id;
251→    const entryName = selectedEntry.name;
252→    setActionsOpen(false);
253→    confirmAlert({
254→      title: `Move "${entryName}" to Trash?`,
