 94→  const [filterValue, setFilterValue] = useState('all');
 95→  const [selectedIndex, setSelectedIndex] = useState(0);
 96→  const [actionsOpen, setActionsOpen] = useState(false);
 97→  const { items: hudItems, show: showHUD } = useHUD();
