 99→  const filteredColors = useMemo(() => {
100→    let colors: ColorItemData[] = MOCK_COLORS;
101→    if (filterValue !== 'all') {
102→      colors = colors.filter(c => c.category === filterValue);
103→    }
104→    return filterColors(colors, query);
105→  }, [
106→    query,
107→    filterValue,
108→  ]);
109→
110→  const selectedColor = filteredColors[selectedIndex];
111→
112→  const handleQueryChange = useCallback((value: string) => {
113→    setQuery(value);
114→    setSelectedIndex(0);
115→    setActionsOpen(false);
116→  }, []);
117→
118→  const handleFilterChange = useCallback((value: string) => {
119→    setFilterValue(value);
120→    setSelectedIndex(0);
121→  }, []);
122→
123→  const handleActiveIndexChange = useCallback((index: number) => {
124→    setSelectedIndex(index);
125→    setActionsOpen(false);
126→  }, []);
127→
128→  const handleCopyColor = useCallback(
129→    (color: ColorItemData) => {
130→      performCopy(color.color, showHUD, {
131→        hudIcon: <ClipboardHUDIcon />,
132→        hudTitle: `Copied ${color.color}`,
133→      });
134→    },
135→    [showHUD],
136→  );
137→
138→  const handleGridAction = useCallback(
139→    (index: number) => {
140→      const color = filteredColors[index];
141→      if (color) {
142→        handleCopyColor(color);
143→      }
144→    },
145→    [
146→      filteredColors,
147→      handleCopyColor,
148→    ],
149→  );
150→
151→  const toggleActions = useCallback(() => {
152→    setActionsOpen(prev => !prev);
153→  }, []);
154→
155→  const closeActions = useCallback(() => {
156→    setActionsOpen(false);
157→  }, []);
158→
159→  useKeyboardShortcut(
160→    {
161→      key: 'k',
162→      meta: true,
163→    },
164→    toggleActions,
165→  );
166→
167→  const dropdownSections: DropdownSection[] = useMemo(
168→    () => [
169→      {
170→        title: 'Actions',
171→        actions: [
172→          {
173→            label: 'Copy Color',
174→            shortcut: <Kbd keys={['↵']} />,
175→            onClick: () => {
176→              if (selectedColor) {
177→                setActionsOpen(false);
178→                handleCopyColor(selectedColor);
179→              }
180→            },
181→          },
182→          createCopyAction(
183→            {
184→              content: selectedColor?.color ?? '',
185→              title: 'Copy Hex',
186→              shortcut: (
187→                <Kbd
188→                  keys={[
189→                    '⌘',
190→                    'C',
191→                  ]}
192→                />
193→              ),
194→              hudIcon: <ClipboardHUDIcon />,
195→              hudTitle: selectedColor
196→                ? `Copied ${selectedColor.color}`
197→                : 'Copied',
198→            },
199→            showHUD,
200→          ),
201→        ],
202→      },
203→    ],
204→    [
205→      selectedColor,
206→      handleCopyColor,
207→      showHUD,
208→    ],
209→  );
210→
211→  const activeDescendantId =
212→    filteredColors.length > 0 ? `grid-item-${selectedIndex}` : undefined;
213→
214→  return (
215→    <>
216→      <SearchBar
217→        value={query}
218→        onChange={handleQueryChange}
219→        activeDescendantId={activeDescendantId}
220→        dropdown={
221→          <SearchDropdown
222→            sections={colorFilterSections}
223→            value={filterValue}
224→            onChange={handleFilterChange}
225→          />
226→        }
227→      />
228→      <div className="color-picker__body">
229→        {filteredColors.length === 0 ? (
230→          <EmptyState
231→            icon={<SearchIcon />}
232→            title="No Colors"
233→            description="Try a different search term"
234→          />
235→        ) : (
236→          <Grid
237→            key={filterValue}
238→            itemCount={filteredColors.length}
239→            columns={4}
240→            onActiveIndexChange={handleActiveIndexChange}
241→            onAction={handleGridAction}
242→          >
243→            {filteredColors.map((color, index) => (
244→              <GridItem
245→                key={color.id}
246→                index={index}
247→                icon={<ColorSwatch color={color.color} />}
248→                title={color.title}
249→                subtitle={color.subtitle}
250→              />
251→            ))}
252→          </Grid>
253→        )}
254→      </div>
255→      <ActionPanel
256→        contextLabel="Color Picker"
257→        actions={[
258→          {
259→            label: 'Copy Color',
260→            shortcut: <Kbd keys={['↵']} />,
261→          },
262→          {
263→            label: 'Actions',
264→            shortcut: (
265→              <Kbd
266→                keys={[
267→                  '⌘',
268→                  'K',
269→                ]}
270→              />
271→            ),
272→            onClick: toggleActions,
273→          },
274→        ]}
275→        dropdownOpen={actionsOpen}
276→        dropdownSections={dropdownSections}
277→        onDropdownClose={closeActions}
278→      />
279→      <HUDContainer items={hudItems} />
280→    </>
281→  );
282→}
